import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionFixed {

    public static void main(String[] args) {
        try {
            // Simulating user input
            String[] userInput = {"ls", "-l"};

            // Execute the command securely using ProcessBuilder
            ProcessBuilder processBuilder = new ProcessBuilder(userInput);
            Process process = processBuilder.start();

            // Read the output of the executed command
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

